import fs from 'node:fs';
import path from 'node:path';
import crypto from 'node:crypto';

const root = process.cwd();
const out = path.join(root, 'artifacts', 'holy-grail-proof-run-001');
fs.rmSync(out, { recursive: true, force: true });
fs.mkdirSync(out, { recursive: true });
const now = new Date().toISOString();
const hash = (obj) => crypto.createHash('sha256').update(JSON.stringify(obj)).digest('hex');
const write = (name, obj) => fs.writeFileSync(path.join(out, name), typeof obj === 'string' ? obj : JSON.stringify(obj, null, 2));

const mission = { missionId: 'HG-PR001-DEMO', title: 'Proof-gated open-ended work demo', createdAt: now, publicSafe: true, noUserData: true, objective: 'Demonstrate the GoalOS loop from mission to harder mission using a synthetic public-safe example.', doneCondition: 'Evidence Docket, verifier report, risk ledger, Chronicle entry, capability package, and settlement signal exist.', valueMoved: 0 };
const evidence = { docketId: 'ED-HG-PR001', missionId: mission.missionId, publicPrivateBoundary: 'Public-safe synthetic example only.', claims: [{ claim: 'GoalOS can represent work as gated proof states.', support: 'Browser-local deterministic demo artifacts.', status: 'supported_for_demo' }, { claim: 'The public demo moves value.', support: 'None.', status: 'rejected' }], replayPath: 'Open proof-run-001.html and click Launch proof loop.' };
const verifier = { verdict: 'demo_pass', unsupportedClaimsRejected: true, observations: ['No user input required.', 'No wallet connection.', 'No value moved.', 'Proof stages complete.'] };
const risk = { riskClass: 'public_demo', controls: ['no forms', 'no uploads', 'no cookies', 'no analytics', 'no wallet', 'no payments'], valueMoved: 0 };
const chronicle = { entryId: 'CHR-HG-PR001', remembers: ['mission', 'proof', 'validation', 'capability'], reusableFor: 'future public-safe demo missions' };
const capability = { packageId: 'CAP-HG-PR001', capability: 'Browser-local proof loop explanation and demo', reuseBoundary: 'Educational and public-site demonstration only.' };
const settlement = { type: 'settlement_signal', tokenReference: '$AGIALPHA external Ethereum Mainnet token reference', valueMoved: 0, boundary: 'No sale, custody, brokerage, redemption, staking, or public-site settlement.' };
const receipt = { receiptId: 'MR-HG-PR001', missionHash: hash(mission), evidenceHash: hash(evidence), verifierHash: hash(verifier), decision: 'accepted_for_demo', humanGate: 'required for real missions', issuedAt: now };
write('mission-contract.json', mission);
write('evidence-docket.json', evidence);
write('verifier-report.json', verifier);
write('risk-ledger.json', risk);
write('chronicle-entry.json', chronicle);
write('capability-package.json', capability);
write('settlement-signal.json', settlement);
write('mission-receipt.json', receipt);
write('README.md', `# GoalOS Proof Run 001 — Browser Demo Artifact\n\nThis is a public-safe synthetic demo bundle generated by GitHub Actions.\n\n- No user data\n- No uploads\n- No wallet\n- No value moved\n- No investment, legal, financial, or settlement advice\n\nOpen the production browser demo at https://montrealai.github.io/goalos-signoff-pro/proof-run-001.html.\n`);
console.log(`GoalOS Holy Grail demo artifact bundle generated at ${out}`);
